// src/components/ParticlesBg.jsx
import { useEffect, useRef } from 'react';

export default function ParticlesBg() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animId;

    let width = canvas.offsetWidth;
    let height = canvas.offsetHeight;

    // --- FIX PARA MÓVILES: Detectamos si es táctil ---
    const isTouchDevice = ('ontouchstart' in window) || (navigator.maxTouchPoints > 0);
    const isMobile = window.innerWidth < 850;

    const resize = () => {
      width = canvas.parentElement.offsetWidth;
      height = canvas.parentElement.offsetHeight;
      
      // FIX PARA PANTALLAS RETINA (iPhone/Android Alta Gama)
      // Evita que el canvas se vea borroso o pixelado
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      ctx.scale(dpr, dpr);
    };
    
    resize();

    const ro = new ResizeObserver(resize);
    if (canvas.parentElement) ro.observe(canvas.parentElement);

    // En móvil ponemos menos partículas para un look más limpio y mejor rendimiento
    const PARTICLE_COUNT = isMobile ? 50 : 160; 
    
    let mouse = { x: null, y: null, active: false, radius: 220 };

    const onMove = (e) => {
      // Si es táctil, ignoramos para no marear al hacer scroll
      if (isTouchDevice) return; 
      const rect = canvas.getBoundingClientRect();
      mouse.x = e.clientX - rect.left;
      mouse.y = e.clientY - rect.top;
      mouse.active = true;
    };
    
    const onLeave = () => { mouse.active = false; };

    if (canvas.parentElement && !isTouchDevice) {
      canvas.parentElement.addEventListener('mousemove', onMove);
      canvas.parentElement.addEventListener('mouseleave', onLeave);
    }

    const particles = Array.from({ length: PARTICLE_COUNT }, () => {
      const angle = Math.random() * Math.PI * 2;
      const speed = Math.random() * (isMobile ? 0.4 : 0.8) + 0.2; 
      return {
        x: Math.random() * width,
        y: Math.random() * height,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        r: Math.random() * 1.5 + 0.5,
        alpha: Math.random() * 0.4 + 0.2,
        phase: Math.random() * 100, 
        speedPhase: Math.random() * 0.02 + 0.005,
      };
    });

    const draw = () => {
      // En móvil borramos la estela más rápido para que sea más sutil
      ctx.fillStyle = isMobile ? 'rgba(10, 10, 12, 0.12)' : 'rgba(10, 10, 12, 0.06)'; 
      ctx.fillRect(0, 0, width, height);

      particles.forEach(p => {
        p.phase += p.speedPhase;

        // Movimiento base de flujo caótico sutil
        let ax = Math.sin(p.phase + p.y * 0.005) * 0.12;
        let ay = Math.cos(p.phase + p.x * 0.005) * 0.12;

        // El vórtice solo funciona si NO es táctil (PC)
        if (!isTouchDevice && mouse.active && mouse.x !== null && mouse.y !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < mouse.radius) {
            const force = (mouse.radius - dist) / mouse.radius;
            
            const pullX = (dx / dist) * force * 0.4;
            const pullY = (dy / dist) * force * 0.4;

            const tangentX = (-dy / dist) * force * 1.8;
            const tangentY = (dx / dist) * force * 1.8;

            ax += pullX + tangentX;
            ay += pullY + tangentY;
          }
        }

        p.vx += ax;
        p.vy += ay;
        p.vx *= 0.96;
        p.vy *= 0.96;

        p.x += p.vx;
        p.y += p.vy;

        if (p.x < -20) p.x = width + 20;
        if (p.x > width + 20) p.x = -20;
        if (p.y < -20) p.y = height + 20;
        if (p.y > width + 20) p.y = -20;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);

        let finalAlpha = p.alpha;
        let finalColor = `rgba(232, 58, 58, ${finalAlpha})`;

        if (!isTouchDevice && mouse.active && mouse.x !== null && mouse.y !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < mouse.radius) {
            const factor = (mouse.radius - dist) / mouse.radius;
            finalAlpha = p.alpha + factor * 0.6;
            finalColor = `rgba(${232 + Math.floor(factor * 23)}, ${58 + Math.floor(factor * 40)}, 58, ${finalAlpha})`;
          }
        }

        ctx.fillStyle = finalColor;
        ctx.fill();
      });

      animId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(animId);
      ro.disconnect();
      if (canvas.parentElement) {
        canvas.parentElement.removeEventListener('mousemove', onMove);
        canvas.parentElement.removeEventListener('mouseleave', onLeave);
      }
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'absolute',
        inset: 0,
        width: '100%',
        height: '100%',
        zIndex: 0,
        pointerEvents: 'none',
      }}
    />
  );
}
